// Solution
from sys import stdin

class Solution:
    def generateFibonacci(self, n: int) -> str:
        if n == 0:
            return "0"
        elif n == 1:
            return "0 1"
        else:
            a, b = 0, 1
            result = "0 1"
            for i in range(2, n+1):
                result += " " + str(a + b)
                a, b = b, a + b
            return result

if __name__ == '__main__':
    n = int(stdin.readline())
    solution = Solution()
    print(solution.generateFibonacci(n))

